const tickerData = $input.first().json;
const originalData = $('Parse Request').item.json;

const price = parseFloat(tickerData.lastPrice).toFixed(2);
const change = parseFloat(tickerData.priceChangePercent).toFixed(2);
const high = parseFloat(tickerData.highPrice).toFixed(2);
const low = parseFloat(tickerData.lowPrice).toFixed(2);
const trend = change >= 0 ? '📈' : '📉';
const changeSign = change >= 0 ? '+' : '';

const text = `💰 *${originalData.baseCurrency}/${originalData.quoteCurrency}*

${trend} *Price:* ${price} ${originalData.quoteCurrency}
📊 *24h change:* ${changeSign}${change}%
📈 *24h high:* ${high}
📉 *24h low:* ${low}

📈 [Open chart on TradingView](${originalData.chartLink})`;

return [{
  chat_id: originalData.chat_id,
  text: text,
  parse_mode: "Markdown",
  business_connection_id: originalData.business_connection_id,
  reply_to_message_id: originalData.reply_to_message_id
}];

const forexData = $input.first().json;
const originalData = $('Parse Request').item.json;

let price = null;
let change = null;

if (forexData.data && forexData.data[0] && forexData.data[0].d) {
  price = parseFloat(forexData.data[0].d[0]).toFixed(4);
  change = parseFloat(forexData.data[0].d[1]).toFixed(2);
}

if (!price) {
  return [{
    chat_id: originalData.chat_id,  
    text: "❌ Failed to get currency rate. Please try again later.",
    business_connection_id: originalData.business_connection_id,
    reply_to_message_id: originalData.reply_to_message_id
  }];
}

const trend = change >= 0 ? '📈' : '📉';
const changeSign = change >= 0 ? '+' : '';

const text = `💱 *${originalData.baseCurrency}/${originalData.quoteCurrency}*

${trend} *Rate:* ${price}
📊 *Change:* ${changeSign}${change}%

📈 [Open chart on TradingView](${originalData.chartLink})`;

return [{
  chat_id: originalData.chat_id, 
  text: text,
  parse_mode: "Markdown",
  business_connection_id: originalData.business_connection_id,
  reply_to_message_id: originalData.reply_to_message_id
}];

const body = $input.first().json.body;
const message = body.business_message;
const text = message.text.toLowerCase();
const chatId = message.chat.id;
const businessId = message.business_connection_id;
const messageId = message.message_id;

const cleanText = text.replace(/rate\s*/i, '').trim();

const patterns = [

  { regex: /^([A-Za-z]{3,6})\/([A-Za-z]{3,6})$/, type: 'separated' },

  { regex: /^([A-Za-z]{3,8})([A-Za-z]{3,4})$/, type: 'joined' },

  { regex: /^([A-Za-z]{3,6})$/, type: 'single' }
];

let baseCurrency = null;
let quoteCurrency = null;
let matched = false;

for (const pattern of patterns) {
  const match = cleanText.match(pattern.regex);
  if (match) {
    baseCurrency = match[1].toUpperCase();
    quoteCurrency = match[2] ? match[2].toUpperCase() : null;
    matched = true;
    break;
  }
}

const specialCrypto = ['ETHUSDT', 'MATICUSDT', 'AVAXUSDT', 'DOTUSDT', 'LINKUSDT', 'TONUSDT'];
for (const crypto of specialCrypto) {
  if (cleanText === crypto.toLowerCase()) {
    baseCurrency = crypto.replace('USDT', '');
    quoteCurrency = 'USDT';
    matched = true;
    break;
  }
}

if (!matched || !baseCurrency) {
  return [{
    chat_id: chatId,
    text: "❌ PAIR NOT FOUND. Examples:\n• Rate BTC/USDT\n• Rate ETHUSDT\n• Rate USDRUB",
    business_connection_id: businessId,
    reply_to_message_id: messageId
  }];
}

const cryptoList = ['BTC', 'ETH', 'BNB', 'SOL', 'XRP', 'ADA', 'DOGE', 'TON', 'LINK', 'TRX', 'MATIC', 'DOT', 'AVAX'];
const fiatList = ['USD', 'RUB', 'EUR', 'GBP', 'JPY', 'CNY', 'CHF', 'AED', 'THB', 'TRY'];

// Determine pair type
const isBaseCrypto = cryptoList.includes(baseCurrency);
const isQuoteCrypto = quoteCurrency ? cryptoList.includes(quoteCurrency) : false;
const isBaseFiat = fiatList.includes(baseCurrency);
const isQuoteFiat = quoteCurrency ? fiatList.includes(quoteCurrency) : false;

let exchangeType = '';
let tradingViewSymbol = '';
let displayPair = '';

if ((isBaseCrypto || isQuoteCrypto) && !(isBaseFiat && isQuoteFiat)) {

  exchangeType = 'crypto';
  if (!quoteCurrency) quoteCurrency = 'USDT';
  displayPair = `${baseCurrency}/${quoteCurrency}`;
  tradingViewSymbol = `BINANCE:${baseCurrency}${quoteCurrency}`;
} else {

  exchangeType = 'forex';
  if (!quoteCurrency) {
    quoteCurrency = 'USD';
  }
  displayPair = `${baseCurrency}/${quoteCurrency}`;
  tradingViewSymbol = `FX_IDC:${baseCurrency}${quoteCurrency}`;
}

const chartLink = `https://www.tradingview.com/chart/?symbol=${tradingViewSymbol}`;

let binanceSymbol = null;
if (exchangeType === 'crypto') {
  binanceSymbol = `${baseCurrency}${quoteCurrency}`;
}

return [{
  chat_id: chatId,
  baseCurrency: baseCurrency,
  quoteCurrency: quoteCurrency,
  displayPair: displayPair,
  exchangeType: exchangeType,
  tradingViewSymbol: tradingViewSymbol,
  binanceSymbol: binanceSymbol,
  chartLink: chartLink,
  business_connection_id: businessId,
  reply_to_message_id: messageId
}];
